using Microsoft.AspNetCore.Components;
using sv_9335e0d76d27422aa4d1e8c995c5b977;
using sv_9335e0d76d27422aa4d1e8c995c5b977.Components;

var builder = WebApplication.CreateBuilder(args);

// Add services to the container.
builder.Services.AddRazorComponents()
    .AddInteractiveServerComponents();

// Theme state: CascadingValueSource crosses render-mode boundaries,
// and scoped lifetime gives each circuit its own independent theme.
