    var theme = new ThemeInfo();
    return new CascadingValueSource<ThemeInfo>(theme, isFixed: false);
});
builder.Services.AddScoped<ThemeService>();

arguments.file_text:
@* Shows the current theme mode and accent color — works in static and interactive contexts *@

<span class="badge" style="background-color: @(Theme?.AccentColor ?? "#0d6efd")">
    @(Theme?.Mode.ToString() ?? "Light") mode
</span>

@code {
    [CascadingParameter]
    private ThemeInfo? Theme { get; set; }
}

@page "/settings"
@rendermode InteractiveServer
@inject ThemeService ThemeService

<PageTitle>Settings</PageTitle>

<h2>User Preferences</h2>

<div class="mb-3">
    <label class="form-label fw-bold">Theme Mode</label>
    <div>
        @foreach (var mode in Enum.GetValues<ThemeMode>())
        {
            <div class="form-check form-check-inline">
                <input class="form-check-input" type="radio" name="themeMode"
                       id="mode-@mode" value="@mode"
                       checked="@(selectedMode == mode)"
                       @onchange="() => OnModeChanged(mode)" />
                <label class="form-check-label" for="mode-@mode">@mode</label>
            </div>
        }
    </div>
</div>

<div class="mb-3">
    <label class="form-label fw-bold" for="accentColor">Accent Color</label>
    <input type="color" class="form-control form-control-color" id="accentColor"
           value="@accentColor" @onchange="OnColorChanged" />
</div>

<p>
    Current:
    <span class="badge" style="background-color: @accentColor">
        @selectedMode mode
    </span>
</p>

@code {
    private ThemeMode selectedMode;
    private string accentColor = "#0d6efd";

    [CascadingParameter]
    private ThemeInfo? Theme { get; set; }

    protected override void OnParametersSet()
    {
        if (Theme is not null)
        {
            selectedMode = Theme.Mode;
            accentColor = Theme.AccentColor;
        }
    }

    private async Task OnModeChanged(ThemeMode mode)
    {
        selectedMode = mode;
        await ThemeService.UpdateAsync(selectedMode, accentColor);
    }

    private async Task OnColorChanged(ChangeEventArgs e)
    {
        accentColor = e.Value?.ToString() ?? accentColor;
        await ThemeService.UpdateAsync(selectedMode, accentColor);
    }
}

